examples.source:
.box { width: 140px; height: 70px; border: 2px solid #6366f1; display: inline-block; margin: 4px; vertical-align: top; font-size: 12px; }
.v { overflow: visible; }
.h { overflow: hidden; }
.a { overflow: auto; }

img { width: 90px; margin: 4px; }
.o3 { opacity: 0.3; }
.o6 { opacity: 0.6; }
.fade { opacity: 0.5; }
.fade:hover { opacity: 1; }

.c { display: inline-block; background: #e0e7ff; padding: 8px 14px; margin: 4px; border-radius: 6px; }
.p { cursor: pointer; }
.w { cursor: wait; }
.n { cursor: not-allowed; }
.h { cursor: help; }
